      "evidence": [
        {"source": "extracted_output.turns[0].session_summary.accumulated_fields", "value": {}}
      ]
    },
    {
      "expectation_id": "意图阶段正确路由",
      "fulfillment_status": "not_fulfilled",
      "suspected_locations": [
